import{_ as a,o as e,c as r,ag as l}from"./chunks/framework.CAXxHpAX.js";const c=JSON.parse('{"title":"本地记忆插件 MemOS","description":"","frontmatter":{},"headers":[],"relativePath":"06-memos.md","filePath":"06-memos.md"}'),i={name:"06-memos.md"};function o(s,t,n,h,d,m){return e(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="本地记忆插件-memos" tabindex="-1">本地记忆插件 MemOS <a class="header-anchor" href="#本地记忆插件-memos" aria-label="Permalink to &quot;本地记忆插件 MemOS&quot;">​</a></h1><p>来源：<a href="https://mp.weixin.qq.com/s?__biz=MzY5MTA4NTg5NQ==&amp;mid=2247484337&amp;idx=1&amp;sn=9b60207a8856cf6325c071d964695aaf" target="_blank" rel="noreferrer">ITADN技术部落 - 10万星神级Hermes迎来外挂！本地记忆神器上线</a></p><blockquote><p>MemTensor 团队为 Hermes 开发的本地私有化记忆插件，基于 MemOS 开源项目</p></blockquote><h2 id="hermes-原生记忆的硬伤" tabindex="-1">Hermes 原生记忆的硬伤 <a class="header-anchor" href="#hermes-原生记忆的硬伤" aria-label="Permalink to &quot;Hermes 原生记忆的硬伤&quot;">​</a></h2><ul><li>所有对话轮次直接存入 SQLite 数据库</li><li>检索仅依靠基础文本字符匹配</li><li><strong>同一段信息在多轮对话反复提及，就会生成大量重复条目</strong></li><li><strong>无法分辨信息时效性</strong>，新指令和旧指令冲突时无法识别</li></ul><p><strong>典型案例</strong>：告知 AI &quot;正在减脂，每天1800大卡&quot;，一周后说&quot;放弃减脂恢复日常饮食&quot;。后续 AI 依然推荐低卡饮食方案，因为两条矛盾信息全部被保存，原生系统无法分辨。</p><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><h3 id="智能写入去重-自动更新旧记忆" tabindex="-1">智能写入去重，自动更新旧记忆 <a class="header-anchor" href="#智能写入去重-自动更新旧记忆" aria-label="Permalink to &quot;智能写入去重，自动更新旧记忆&quot;">​</a></h3><p>处理链路：<strong>语义拆分切片 → 大模型智能总结 → 向量数据转化 → 智能比对去重</strong></p><ul><li><strong>全新内容</strong>：单独存入</li><li><strong>重复内容</strong>：智能合并</li><li><strong>旧信息更新</strong>：自动识别并合并，同时完整留存变更轨迹</li></ul><h3 id="混合检索引擎" tabindex="-1">混合检索引擎 <a class="header-anchor" href="#混合检索引擎" aria-label="Permalink to &quot;混合检索引擎&quot;">​</a></h3><ul><li><strong>全文检索 + 向量语义检索</strong> 双引擎并行</li><li>融合排序、冗余剔除、时间权重衰减、相关性多层过滤</li><li>提问话术和原始记录用词不一致时，语义层面仍可精准召回</li><li>每轮对话开启时，系统自动根据用户最新提问预检索相关记忆，自动注入上下文</li></ul><h2 id="技能生成升级" tabindex="-1">技能生成升级 <a class="header-anchor" href="#技能生成升级" aria-label="Permalink to &quot;技能生成升级&quot;">​</a></h2><p>MemOS 插件支持<strong>三级模型独立配置</strong>：</p><table tabindex="0"><thead><tr><th>层级</th><th>用途</th></tr></thead><tbody><tr><td>向量嵌入</td><td>轻量模型，降低算力消耗</td></tr><tr><td>内容摘要</td><td>中端模型，平衡效果与速度</td></tr><tr><td>高阶技能生成</td><td>高性能大模型（可切换）</td></tr></tbody></table><ul><li>内置规则过滤 + 模型质量审核机制</li><li>智能降级容错：高阶模型异常时自动切换中端，再次异常则调用原生 Hermes 模型</li></ul><h2 id="多-agent-协同" tabindex="-1">多 Agent 协同 <a class="header-anchor" href="#多-agent-协同" aria-label="Permalink to &quot;多 Agent 协同&quot;">​</a></h2><ul><li><strong>单机多实例协同</strong>：每个 Agent 拥有私有独立记忆空间，同时可共享公共知识库与通用技能</li><li><strong>跨设备 Hub-Client 架构</strong>：个人隐私数据始终留存本地，仅主动共享的内容对团队开放</li></ul><h2 id="可视化管理面板" tabindex="-1">可视化管理面板 <a class="header-anchor" href="#可视化管理面板" aria-label="Permalink to &quot;可视化管理面板&quot;">​</a></h2><p>插件部署完成后自动生成 Web 管理后台：<strong><a href="http://127.0.0.1:18901" target="_blank" rel="noreferrer">http://127.0.0.1:18901</a></strong></p><p>7 大功能模块：记忆浏览检索、任务进程管理、技能库管控、数据统计分析、工具调用日志、数据导入导出、参数在线配置</p><h2 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h2><h3 id="前置要求" tabindex="-1">前置要求 <a class="header-anchor" href="#前置要求" aria-label="Permalink to &quot;前置要求&quot;">​</a></h3><ul><li>Node.js ≥ 18</li><li>Python 3 环境</li><li>已完成 Hermes Agent 本体部署</li></ul><h3 id="一键安装" tabindex="-1">一键安装 <a class="header-anchor" href="#一键安装" aria-label="Permalink to &quot;一键安装&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/MemTensor/MemOS/openclaw-local-plugin-20260408/apps/memos-local-plugin/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div><p>安装脚本自动完成：环境检测 → 依赖补齐 → 插件包下载 → 配置依赖 → 挂载插件目录 → 修改配置文件 → 校验加载状态 → 启动后台守护进程与可视化面板</p><h3 id="官方文档" tabindex="-1">官方文档 <a class="header-anchor" href="#官方文档" aria-label="Permalink to &quot;官方文档&quot;">​</a></h3><p><a href="https://memos-docs.openmem.net/cn/openclaw/hermes_local_plugin" target="_blank" rel="noreferrer">https://memos-docs.openmem.net/cn/openclaw/hermes_local_plugin</a></p><h2 id="优缺点" tabindex="-1">优缺点 <a class="header-anchor" href="#优缺点" aria-label="Permalink to &quot;优缺点&quot;">​</a></h2><table tabindex="0"><thead><tr><th>优势</th><th>说明</th></tr></thead><tbody><tr><td>记忆检索准确率显著提升</td><td>此前往回失败的历史信息基本都能精准召回</td></tr><tr><td>智能去重合并效果显著</td><td>杜绝同一条信息重复存储大量副本</td></tr><tr><td>全程本地私有化</td><td>隐私数据安全无外泄风险</td></tr><tr><td>技能生成质量更高</td><td>三级模型独立配置+质量审核</td></tr><tr><td>后台管理便捷</td><td>Web 界面摆脱命令行</td></tr></tbody></table><table tabindex="0"><thead><tr><th>待改进</th><th>说明</th></tr></thead><tbody><tr><td>首次调用消耗 Token</td><td>高频长期使用场景优势集中体现，偶尔零散使用感知差异不明显</td></tr></tbody></table><h2 id="开源地址" tabindex="-1">开源地址 <a class="header-anchor" href="#开源地址" aria-label="Permalink to &quot;开源地址&quot;">​</a></h2><p><a href="https://github.com/MemTensor/MemOS/tree/main/apps/memos-local-plugin" target="_blank" rel="noreferrer">https://github.com/MemTensor/MemOS/tree/main/apps/memos-local-plugin</a></p>',34)])])}const u=a(i,[["render",o]]);export{c as __pageData,u as default};
